  if (!conn_result) {
    // Handle connection error
    return;
  }
  auto conn = conn_result.value();

  // Generate delete statement using sqlgen::delete_from
  auto delete_stmt = sqlgen::delete_from<std::vector<Student>> 
                   | sqlgen::where("SNo"_c == record_id);

  // Execute the delete operation
