#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_product_sales_report {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string category;
};

struct Sale {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct CategoryReport {
  std::string category;
  int total_qty;
  double total_amt;
};

struct ProductSalesReport {
  static constexpr const char* tablename = "ProductSalesReport";
  static constexpr bool is_view = true;
  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
    using namespace sqlgen::literals;

    // 1. Connect to the database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

    // 2. Build the query using sqlgen's fluent interface
    auto query = sqlgen::select_from<Product>("category"_c)
        | sqlgen::inner_join<Sale>("product_id"_c == "product_id"_c)
        | sqlgen::group_by("category"_c)
        | sqlgen::select(
            "category"_c,
            sqlgen::sum("quantity"_c).as<"total_qty">(),
            sqlgen::sum("amount"_c).as<"total_amt">()
        )
        | sqlgen::having(sqlgen::sum("amount"_c) > 5000.0);

    // 3. Execute the query and map results to CategoryReport
    auto result = query(conn).value();

    // 4. Convert the result to the required format
    std::vector<CategoryReport> reports;
    for (const auto& row : result) {
        reports.push_back({
            .category = row.category,
            .total_qty = row.total_qty,
            .total_amt = row.total_amt
        });
    }

    return reports;
}

}  // namespace query_product_sales_report
```

