bool update_set_operations() {
  // 1. Connect to the SQLite database "test_db.sqlite"
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // 2. Create the Account table by writing an empty container of Account
  std::vector<Account> empty_accounts;
  auto create_result = sqlgen::write(conn, empty_accounts);
