      .account_id = 1,
      .balance = 1000.0,
      .status = "active"
  };

  // Write the updated account to perform the update operation
  std::vector<Account> update_data{updated_account};
  auto update_result = sqlgen::write(conn, update_data);
  if (!update_result) {
    return false;
  }

